// Solution
function fixMongoDBProjection(document, projection) {
    let result = {};

    // Iterate over the fields in the document
    for (let field in document) {
        // Check if the field is specified in the projection
        if (projection[field] === true) {
            // If the field is specified, include it in the result
            result[field] = document[field];
        } else if (typeof document[field] === 'object') {
            // If the field is an object, recursively call the function
            let subfield = fixMongoDBProjection(document[field], projection[field]);
            if (Object.keys(subfield).length > 0) {
                result[field] = subfield;
            }
        }
    }

    return result;
}

