class Solution:
    def fix_mongodb_projection(self, document, projection):
        result = {}

        # Iterate over the fields in the document
        for field in document:
            # Check if the field is specified in the projection
            if field in projection and projection[field] is True:
                # If the field is specified, include it in the result
                result[field] = document[field]
            elif isinstance(document[field], dict):
                # If the field is an object, recursively call the function
                subfield = self.fix_mongodb_projection(document[field], projection[field])
                if len(subfield) > 0:
                    result[field] = subfield

        return result
